import React, { useRef, useState, useEffect, useMemo } from "react";
import data from "../../data/portfolio.json";

const { temas, tags, usos } = data.dicts;

function useClickOutside(ref, callback) {
  useEffect(() => {
    const handle = (e) => {
      if (ref.current && !ref.current.contains(e.target)) callback();
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [ref, callback]);
}

export default function FilterPanel({
  activeFilters,
  setActiveFilters,
  filteredCount,
}) {
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [openGroup, setOpenGroup] = useState(null);
  const filtersRef = useRef(null);

  useClickOutside(filtersRef, () => setFiltersOpen(false));

  const groups = useMemo(
    () => [
      { label: "Temas", items: temas },
      { label: "Tags", items: tags },
      { label: "Usos", items: usos },
    ],
    []
  );

  const toggleFilter = (filter) => {
    setActiveFilters((prev) =>
      prev.includes(filter)
        ? prev.filter((f) => f !== filter)
        : [...prev, filter]
    );
  };

  return (
    <div
      style={{
        background: "#fff",
        padding: "18px 20px",
        borderBottom: "1px solid #eee",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "12px",
        }}
      >
        {/* RESULTADOS */}
        <div
          style={{
            fontSize: "14px",
            color: "#444",
            whiteSpace: "nowrap",
            fontFamily: "'Montserrat', sans-serif",
          }}
        >
          {filteredCount} resultado{filteredCount === 1 ? "" : "s"}
        </div>

        {/* BARRA FILTROS (ACORDEÓN) */}
        <div ref={filtersRef} style={{ flex: 1, maxWidth: "500px" }}>
          <button
            type="button"
            onClick={() => setFiltersOpen((v) => !v)}
            style={{
              width: "100%",
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              padding: "10px 14px",
              borderRadius: "99px",
              border: "1px solid rgba(120,80,200,0.5)",
              background: "#fff",
              cursor: "pointer",
              fontFamily: "'Montserrat', sans-serif",
            }}
          >
            {/* IZQUIERDA: chips o texto */}
            <span style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
              {activeFilters.length === 0 ? (
                <span style={{ color: "#aaa" }}>Filtrar</span>
              ) : (
                activeFilters.map((filter) => (
                  <span
                    key={filter}
                    onClick={(e) => {
                      e.stopPropagation();
                      setActiveFilters((prev) =>
                        prev.filter((f) => f !== filter)
                      );
                    }}
                    style={{
                      display: "inline-flex",
                      alignItems: "center",
                      gap: "6px",
                      padding: "4px 10px",
                      borderRadius: "999px",
                      border: "1px solid #ccc",
                      background: "#fff",
                      fontSize: "12px",
                      cursor: "pointer",
                    }}
                  >
                    {filter}
                    <span style={{ fontSize: "11px", color: "#888" }}>✕</span>
                  </span>
                ))
              )}
            </span>

            {/* DERECHA: X global */}
            {activeFilters.length > 0 && (
              <span
                onClick={(e) => {
                  e.stopPropagation();
                  setActiveFilters([]);
                }}
                onMouseEnter={(e) => (e.currentTarget.style.color = "#000")}
                onMouseLeave={(e) => (e.currentTarget.style.color = "#888")}
                style={{
                  marginLeft: "10px",
                  fontSize: "14px",
                  color: "#888",
                  cursor: "pointer",
                  flexShrink: 0,
                }}
              >
                ✕
              </span>
            )}
          </button>
        </div>
      </div>

      {/* ACORDEÓN DE GRUPOS */}
      <div
        style={{
          marginTop: "12px",
          padding: filtersOpen ? "12px 14px" : "0 14px",
          border: "1px solid #e6e6e6",
          borderRadius: "14px",
          background: "#fafafa",
          display: "flex",
          flexWrap: "wrap",
          gap: "20px",
          maxWidth: "575px",
          width: "100%",
          maxHeight: filtersOpen ? "500px" : "0px",
          overflow: "hidden",
          opacity: filtersOpen ? 1 : 0,
          transition:
            "max-height 0.3s ease, opacity 0.2s ease, padding 0.2s ease",
        }}
      >
        {groups.map((group) => {
          const isOpen = openGroup === group.label;
          return (
            <div
              key={group.label}
              style={{
                display: "flex",
                flexDirection: "column",
                minWidth: "160px",
              }}
            >
              <div
                onClick={() => setOpenGroup(isOpen ? null : group.label)}
                style={{
                  cursor: "pointer",
                  fontWeight: "bold",
                  fontSize: "14px",
                  marginBottom: "6px",
                  color: "#0b1f4d",
                  fontFamily: "'Montserrat', sans-serif",
                }}
              >
                {group.label}
              </div>
              {isOpen && (
                <div style={{ paddingLeft: "8px" }}>
                  {group.items.map((filter) => {
                    const active = activeFilters.includes(filter);
                    return (
                      <div
                        key={filter}
                        onClick={() => toggleFilter(filter)}
                        role="button"
                        tabIndex={0}
                        onKeyDown={(e) => {
                          if (e.key === "Enter" || e.key === " ") {
                            e.preventDefault();
                            toggleFilter(filter);
                          }
                        }}
                        style={{
                          cursor: "pointer",
                          fontSize: "13px",
                          color: active ? "#0b1f4d" : "#777",
                          padding: "3px 0",
                          fontFamily: "'Montserrat', sans-serif",
                        }}
                      >
                        {filter}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
